export class PersistentVector<T> {
  private static readonly BRANCH_FACTOR = 32;
  private static readonly SHIFT = 5;
  private static readonly MASK = 0x1f;

  private constructor(
    private readonly root: Node<T>,
    private readonly size: number,
    private readonly tailOffset: number,
    private readonly tail: T[]
  ) {}

  static empty<T>(): PersistentVector<T> {
    return new PersistentVector<T>(new Node<T>([]), 0, 0, []);
  }

  get size(): number {
    return this.size;
  }

  get(i: number): T {
    if (i < 0 || i >= this.size) {
      throw new RangeError(`Index ${i} out of range [0, ${this.size})`);
    }

    if (i >= this.tailOffset) {
      return this.tail[i - this.tailOffset];
    }

    const node = this.root;
    let level = this.height();
    let current = node;

    while (level > 0) {
      const index = (i >>> (level * PersistentVector.SHIFT)) & PersistentVector.MASK;
      current = current.children[index]!;
      level--;
    }

    return current.values[i & PersistentVector.MASK]!;
  }

  push(value: T): PersistentVector<T> {
    if (this.tail.length < PersistentVector.BRANCH_FACTOR) {
      return new PersistentVector<T>(
        this.root,
        this.size + 1,
        this.tailOffset,
        [...this.tail, value]
      );
    }

    const newRoot = this.pushTail(this.root, this.size, this.tail);
    const newTailOffset = this.size + 1 - PersistentVector.BRANCH_FACTOR;
    const newTail = [value];

    return new PersistentVector<T>(
      newRoot,
      this.size + 1,
      newTailOffset,
      newTail
    );
  }

  private height(): number {
    if (this.size <= PersistentVector.BRANCH_FACTOR) {
      return 0;
    }
    let height = 0;
    let s = this.size;
    while (s > PersistentVector.BRANCH_FACTOR) {
      s = (s + PersistentVector.BRANCH_FACTOR - 1) >>> PersistentVector.SHIFT;
      height++;
    }
    return height;
  }

  private pushTail(node: Node<T>, index: number, tail: T[]): Node<T> {
    const level = this.height();
    if (level === 0) {
      return new Node<T>([...node.values, ...tail]);
    }

    const childIndex = (index >>> (level * PersistentVector.SHIFT)) & PersistentVector.MASK;
    const newChildren = [...node.children];
    const newChild = this.pushTail(
      node.children[childIndex]!,
      index,
      tail
    );
    newChildren[childIndex] = newChild;

    return new Node<T>(newChildren);
  }
}

